import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

const StepIndicator = ({ current, total }: { current: number; total: number }) => (
  <Row justify="between">
    <Text variant="label">Step {current} of {total}</Text>
    <Progress value={current} max={total} size="md" />
  </Row>
);


export default function Component(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 3,
    features: [] as string[],
    comments: ''
  });

  const [errors, setErrors] = useState({ name: false, email: false });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canNext = useMemo(() => {
    if (step === 1) return formData.name.length > 0 && validateEmail(formData.email);
    return true;
  }, [step, formData]);

  const submit = useAction<ActionSubmitPayload>('submit');

  const handleNext = () => setStep((s) => Math.min(s + 1, 5));


  const handleBack = () => setStep((s) => Math.max(s - 1, 1));
  const handleSubmit = () => submit(formData);

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Input label="Name" value={formData.name} onChange={(v) => {
              setFormData(d => ({ ...d, name: v }));
              setErrors(e => ({ ...e, name: v.length === 0 }));
            }} required error={errors.name ? 'Name is required' : undefined} />

            <Input label="Email" type="email" value={formData.email} onChange={(v) => {
              setFormData(d => ({ ...d, email: v }));
              setErrors(e => ({ ...e, email: !validateEmail(v) }));
            }} required error={errors.email ? 'Invalid email format' : undefined} />
          </Stack>
        );
      case 2:
        return (
          <RadioGroup 
            label="Satisfaction" 
            options={props.satisfactionLabels.map((l, i) => ({ value: (i + 1).toString(), label: l }))}
            value={formData.satisfaction.toString()}
            onChange={(v) => setFormData(d => ({ ...d, satisfaction: parseInt(v) }))}
          />
        );
      case 3:
        return (
          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="label">Feature Interests</Text>
            {props.featureOptions.map(f => (
              <Checkbox 
                key={f} 
                label={f} 
                checked={formData.features.includes(f)}
                onChange={(checked) => setFormData(d => ({
                  ...d, 
                  features: checked ? [...d.features, f] : d.features.filter(x => x !== f)
                }))}
              />
            ))}
          </Stack>
        );
      case 4:
        return (
          <TextArea 
            label="Comments" 
            value={formData.comments} 
            onChange={(v) => setFormData(d => ({ ...d, comments: v }))}
            maxLength={500} 
            showCount
          />
        );
      case 5:
        return (
          <Card>
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3}>Review</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Satisfaction: {props.satisfactionLabels[formData.satisfaction - 1] || 'Not specified'}</Text>

              <Text>Features: {formData.features.join(', ')}</Text>
              <Text>Comments: {formData.comments}</Text>
            </Stack>
          </Card>
        );

    }
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-6)">
          <StepIndicator current={Math.min(step, 4)} total={4} />
          {renderStep()}
          <Row justify="between">
            <Button as={Clickable} variant="ghost" onClick={handleBack} disabled={step === 1}>Back</Button>
            {step < 5 ? (
              <Button as={Clickable} onClick={handleNext} disabled={!canNext}>Next</Button>
            ) : (
              <Button as={Clickable} variant="primary" onClick={handleSubmit}>Submit</Button>
            )}
          </Row>

        </Stack>
      </Card>
    </Container>
  );

}

