interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




const MessageBubble = ({ sender, text, timestamp, isMine, hideHeader }: { sender?: string; text?: string; timestamp?: string; isMine: boolean; hideHeader?: boolean }) => (
  <Stack align={isMine ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
    {!hideHeader && (
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
        {sender} • {timestamp ? new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
      </Text>
    )}
    <Box
      paddingX="var(--ggui-spacing-3)"
      paddingY="var(--ggui-spacing-2)"
      borderRadius="var(--ggui-shape-radius-lg)"
      background={isMine ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
    >
      <Text color={isMine ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}>{text}</Text>
    </Box>
  </Stack>
);



export default function Component(props: Props) {
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  const [messageInput, setMessageInput] = useState('');
  const [messagesList, setMessagesList] = useState(props.messages || []);
  const [typingUsers, setTypingUsers] = useState<Record<string, boolean>>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (message.latest) setMessagesList((prev) => [...prev, message.latest!]);
  }, [message.latest]);

  useEffect(() => {
    if (typing.latest?.sender) {
      setTypingUsers((prev) => ({ ...prev, [typing.latest!.sender as string]: !!typing.latest!.active }));
    }
  }, [typing.latest]);


  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messagesList]);

  const handleSend = useCallback(() => {
    if (!messageInput.trim()) return;
    const now = new Date().toISOString();
    sendMessage({ text: messageInput, timestamp: now });
    setMessagesList((prev) => [...prev, { sender: props.currentUser, text: messageInput, timestamp: now }]);
    setMessageInput('');
  }, [messageInput, props.currentUser, sendMessage]);

  const typingDisplay = useMemo(() => {
    const active = Object.keys(typingUsers).filter((s) => typingUsers[s]);
    return active.length === 0 ? null : active.length === 1 ? `${active[0]} is typing...` : 'Several people are typing...';
  }, [typingUsers]);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4)">
      <Card padding="var(--ggui-spacing-4)" style={{ height: '80vh', display: 'flex', flexDirection: 'column' }}>
        <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-3)" style={{ paddingBottom: 'var(--ggui-spacing-4)', borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
          <Heading level={3}>{props.title}</Heading>
          <Badge>{props.participantCount} online</Badge>
          {typingDisplay && (
            <Text aria-live="polite" variant="caption" color="var(--ggui-color-primary-600)">
              {typingDisplay}
            </Text>
          )}

        </Stack>

        <Box style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4)' }}>
          <Stack gap="var(--ggui-spacing-4)">
            {messagesList.map((msg, i) => {
              const prev = messagesList[i - 1];
              const isGrouped = prev?.sender === msg.sender;
              return (
                <MessageBubble
                  key={i}
                  sender={msg.sender}
                  text={msg.text}
                  timestamp={msg.timestamp}
                  isMine={msg.sender === props.currentUser}
                  hideHeader={isGrouped}
                />
              );
            })}
            <div ref={messagesEndRef} />
          </Stack>
        </Box>


        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" style={{ paddingTop: 'var(--ggui-spacing-4)', borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
          <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                aria-label="Message input"
                value={messageInput}
                onChange={(e: any) => setMessageInput(e.target?.value ?? e)}
                onKeyDown={(e: any) => e.key === 'Enter' && handleSend()}
                placeholder="Type a message..."
              />


          </Box>
          <Button as={Clickable} onClick={handleSend} disabled={!messageInput.trim()}>Send</Button>
        </Stack>
      </Card>
    </Container>
  );
}

