  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions[0] || '',
    role: props.initialProfile.role || props.roleOptions[0] || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });


  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = formData.name.trim() !== '' && isValidEmail(formData.email);

  const nextStep = () => setStep((s) => Math.min(s + 1, 3));
  const prevStep = () => setStep((s) => Math.max(s - 1, 1));
  const submit = () => complete(formData as ActionCompletePayload);

  const progress = (step / 3) * 100;
  const roleOptions = useMemo(() => 
    props.roleOptions.map(r => ({ value: r, label: r })), 
  [props.roleOptions]);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">


      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Row justify="between">
            <Text variant="label">Step {step} of 3</Text>
            <Text variant="label">{Math.round(progress)}% Complete</Text>
          </Row>
          <Progress value={progress} />
        </Stack>

        <Card padding="var(--ggui-spacing-6)">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Profile Setup</Heading>
              <Input label="Name" value={formData.name} onChange={(v) => setFormData(p => ({...p, name: v}))} />
              <Input label="Email" type="email" value={formData.email} onChange={(v) => setFormData(p => ({...p, email: v}))} error={formData.email && !isValidEmail(formData.email) ? 'Invalid email format' : undefined} />
              <Text variant="label">Avatar</Text>
              <Row gap="var(--ggui-spacing-3)">
                {props.avatarOptions.map(avatar => (
                  <Box key={avatar} as={Clickable} onClick={() => setFormData(p => ({...p, avatar}))} 
                    padding="var(--ggui-spacing-2)" borderRadius="var(--ggui-shape-radius-md)" 
                    background={formData.avatar === avatar ? 'var(--ggui-color-primary-100)' : 'transparent'}>
                    <Text size="3xl">{avatar}</Text>
                  </Box>
                ))}
              </Row>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Preferences</Heading>
              <Select label="Role" value={formData.role} options={roleOptions} onChange={(v) => setFormData(p => ({...p, role: v}))} />
              <Toggle label="Enable Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData(p => ({...p, emailNotifications: v}))} />
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Text variant="label">Theme</Text>
                <Toggle label={formData.theme === 'light' ? 'Light Mode' : 'Dark Mode'} checked={formData.theme === 'dark'} onChange={(v) => setFormData(p => ({...p, theme: v ? 'dark' : 'light'}))} />
              </Stack>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review & Confirm</Heading>
              <Box background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-md)">
                <Text>Name: {formData.name}</Text>
                <Text>Email: {formData.email}</Text>
                <Text>Avatar: {formData.avatar}</Text>
                <Text>Role: {formData.role}</Text>
                <Text>Notifications: {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                <Text>Theme: {formData.theme}</Text>
              </Box>
            </Stack>
          )}
        </Card>

        <Row justify="between">
          <Button as={Clickable} variant="ghost" onClick={prevStep} disabled={step === 1}>Go Back</Button>
          {step < 3 ? (
            <Button as={Clickable} onClick={nextStep} disabled={step === 1 && !isStep1Valid}>Next</Button>
          ) : (
            <Button as={Clickable} variant="primary" onClick={submit}>Complete Setup</Button>
          )}

        </Row>
      </Stack>
    </Container>
  );
}
